import bcrypt

def encrypt_sensitive_data(data):
    """
    Encrypts sensitive user data before storing it in the database.

    Args:
        data: The sensitive user data to encrypt.

    Returns:
        The encrypted data.
    """

    # Generate a salt for encryption
    salt = bcrypt.gensalt()

    # Encrypt the data using bcrypt
    encrypted_data = bcrypt.hashpw(data.encode('utf-8'), salt)

    return encrypted_data